#include<bits/stdc++.h>
using namespace std;
long long h[30010],base[210],t[30010];
char c[300010][210];
const int p=131;
int main()
{
    int n,l,s;
    scanf("%d%d%d",&n,&l,&s);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=l;j++)
        {
            cin>>c[i][j];
            h[i]=h[i]*p+c[i][j];
        }
    }
    base[0]=1;
    for(int i=1;i<=l;i++)
    {
        base[i]=base[i-1]*p;
    }
    long long ans=0;
    for(int i=1;i<=l;i++)
    {
        for(int j=1;j<=n;j++)
        {
            t[j]=h[j]-c[j][i]*base[l-i];
        }
        sort(t+1,t+1+n);
        int cnt=1;
        for(int j=1;j<n;j++)
        {
            if(t[j]!=t[j+1])
            {
                cnt=1;
            }
            else
            {
                ans+=cnt;
                cnt++;
            }
        }
    }
    printf("%lld",ans);
    return 0;
}
